  ('generalpolice-8b7f1efc-moex-00372', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-111-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政命令之合法要件，下列敘述何者錯誤？', '["發布命令之主體須為行政機關", "法律若無轉委任之授權，則受委任機關不得再委任其所屬機關發布規章", "法規命令依法應經上級機關核定者，應於核定後始得發布", "法規命令僅於網站上公告，未刊登政府公報或新聞紙，亦屬合法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:36+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
